module.exports = function(eleventyConfig) {
  // Ignore non-page files
  eleventyConfig.ignores.add("SITE-DEV.md");
  // Diary markdown sources are not templates — ignore so Eleventy doesn't try
  // to render them. Their pre-rendered JSON counterparts (generated by the
  // setup/deploy script) live in satsuma-diaries/content/ and are served via
  // passthrough copy.
  eleventyConfig.ignores.add("satsuma-diaries/**");

  // Passthrough copy for static assets (paths relative to input dir)
  eleventyConfig.addPassthroughCopy("css");
  eleventyConfig.addPassthroughCopy("js");
  eleventyConfig.addPassthroughCopy("img");
  // Diary content JSON files are generated at deploy/setup time and served as-is
  eleventyConfig.addPassthroughCopy("satsuma-diaries");

  // Group diary entries (sorted newest-first) by calendar month.
  // Returns [{label: "March 2026", entries: [...]}, ...] so the template
  // can iterate over groups without needing variable mutation inside loops,
  // which Nunjucks doesn't support cleanly.
  eleventyConfig.addFilter("groupByMonth", function(entries) {
    const groups = [];
    let current = null;
    for (const entry of (entries || [])) {
      const ym = entry.date.slice(0, 7); // "2026-03"
      if (!current || current.yearMonth !== ym) {
        const [year, month] = ym.split("-");
        const label = new Date(parseInt(year), parseInt(month) - 1, 1)
          .toLocaleDateString("en-GB", { month: "long", year: "numeric" });
        current = { yearMonth: ym, label, entries: [] };
        groups.push(current);
      }
      current.entries.push(entry);
    }
    return groups;
  });

  // Format "2026-03-29" → "29 Mar" for diary sidebar entry labels
  eleventyConfig.addFilter("formatDiaryDate", function(dateStr) {
    return new Date(dateStr + "T12:00:00Z")
      .toLocaleDateString("en-GB", { day: "numeric", month: "short" });
  });

  return {
    dir: {
      input: ".",
      output: "_site",
      includes: "_includes",
      layouts: "_layouts",
      data: "_data"
    },
    htmlTemplateEngine: "njk",
    markdownTemplateEngine: "njk"
  };
};
